	@Test
	@EnabledIfSystemProperty(named = ENABLE_PROPERTY, matches = "true")
	void compareQuery2PlannerModes(@TempDir File dataDir) throws Exception {
		LmdbStore store = new LmdbStore(dataDir, new LmdbStoreConfig("spoc,ospc,psoc"));
		SailRepository repository = new SailRepository(store);
		repository.init();
		try {
			String queryName = System.getProperty(QUERY_PROPERTY, "query2ThresholdCount");
			String query = queryText(queryName);
			try (SailRepositoryConnection connection = repository.getConnection()) {
				new AASGenerator().generateAndAdd(connection,
						intProperty(PRODUCTION_LINE_COUNT_PROPERTY, 20),
						intProperty(DRIVE_UNIT_COUNT_PROPERTY, 20), intProperty(SENSOR_COUNT_PROPERTY, 20));
			}
			store.getBackingStore().getSketchBasedJoinEstimator().rebuild();

			List<Scenario> scenarios = List.of(
					new Scenario("lmdb-no-cascades", "off", "off", null, null, false),
					new Scenario("cascades-auto", "auto", "off", null, null, false),
					new Scenario("cascades-budgeted", "budgeted", "off", "4096", null, false),
					new Scenario("cascades-exact", "exact", "off", null, null, false),
					new Scenario("cascades-budgeted-legacy-opaque", "budgeted", "off", "4096", null, true),
					new Scenario("cascades-budgeted-standard-fallback", "budgeted", "fallback", "4096", null,
							false));

			List<PlanDigest> digests = new ArrayList<>(scenarios.size());
			try (SailRepositoryConnection connection = repository.getConnection()) {
				for (Scenario scenario : scenarios) {
					digests.add(explainScenario(connection, queryName, query, scenario));
				}
			}

			String report = report(queryName, digests);
			System.out.println(report);
			if (Boolean.getBoolean(ASSERT_GOOD_CASCADES_PROPERTY)) {
				for (PlanDigest digest : digests) {
					if (!digest.scenario().name().startsWith("cascades")) {
						continue;
					}
					assertTrue(digest.bindsRatedPowerBeforePath(), () -> report);
					assertTrue(digest.bindsValueFilterBeforePath(), () -> report);
					assertTrue(!digest.hasBaselineWinner(), () -> report);
					assertTrue(!digest.hasDisconnectedFallback(), () -> report);
				}
			}
		} finally {
			repository.shutDown();
		}
	}

	private static PlanDigest explainScenario(SailRepositoryConnection connection, String queryName, String query,
			Scenario scenario) {
		Map<String, String> previous = scenario.apply();
		try {
			Explanation explanation = connection.prepareTupleQuery(query)
					.explain(Explanation.Level.Optimized);
			String plan = explanation.toString();
			List<TupleExpr> factors = leftDeepFactors((TupleExpr) explanation.tupleExpr());
			PlanDigest digest = PlanDigest.from(queryName, scenario, factors, plan);
			if (Boolean.getBoolean(PRINT_FULL_PLANS_PROPERTY)) {
				System.out.println("\n=== " + scenario.name() + " full plan ===\n" + plan);
			}
			return digest;
		} finally {
			restore(previous);
		}
	}

	private static String queryText(String queryName) {
		if ("query1PropertyProjection".equals(queryName)) {
			return QUERY1_PROPERTY_PROJECTION;
		}
		return QUERY2_THRESHOLD_COUNT;
	}

	private static List<TupleExpr> leftDeepFactors(TupleExpr root) {
		TupleExpr joinIsland = unwrapUnary(root);
		List<TupleExpr> factors = new ArrayList<>();
		collectJoinFactors(joinIsland, factors);
		return List.copyOf(factors);
	}

	private static void collectJoinFactors(TupleExpr tupleExpr, List<TupleExpr> factors) {
		TupleExpr unwrapped = unwrapUnary(tupleExpr);
		if (unwrapped instanceof Join join) {
			collectJoinFactors(join.getLeftArg(), factors);
			collectJoinFactors(join.getRightArg(), factors);
		} else if (unwrapped != null) {
			factors.add(unwrapped);
		}
	}

	private static TupleExpr unwrapUnary(TupleExpr tupleExpr) {
		TupleExpr current = tupleExpr;
		while (current instanceof UnaryTupleOperator unary) {
			current = unary.getArg();
		}
		return current;
	}

